select count(*) as tar from teacher t where t.id != #{uid}
and t.unitid = #{unitid}
and t.depid = #{depid}
and t.roleid = #{roleid}
and roleID in (3,4,5,6)
and roleID in (3,4,5,6,7) and unitid = (select unitid from teacher where name = #{username})
and roleID in (4,5,6) and depid = (select depid from teacher where name = #{username})
and roleID in (4,5) and depid = (select depid from teacher where name = #{username})
and roleID in (4,5) and depid = (select depid from teacher where name = #{username})
and (name like '%'||#{uname}||'%' or real_name like '%'||#{uname}||'%')

select t2.id as id,t2.name as username,t2.roleid as roleid from teacher t2 where t2.roleid='2' and t2.id!=#{uid}
union select t.id as id,t.name as username,t.roleid as roleid from teacher t where t.depid=(select depid from teacher where id=#{uid}) and t.roleid in('4','5','6') and t.id!=#{uid} union select t.id as id,t.name as username,t.roleid as roleid from teacher t where t.unitid=(select unitid from teacher where id=#{uid}) and t.roleid in('3') and t.id!=#{uid}
union select t.id as id,t.name as username,t.roleid as roleid from teacher t where t.unitid=(select unitid from teacher where id=#{uid}) and t.id!=#{uid} and t.depid=#{deptId,jdbcType=VARCHAR} and t.roleid in('2','3','7')
union select t.id as id,t.name as username,t.roleid as roleid from teacher t where t.unitid=#{unitId,jdbcType=VARCHAR} and t.roleid in('2','3','7') union select t.id as id,t.name as username,t.roleid as roleid from teacher t where t.depid=#{deptId,jdbcType=VARCHAR} and t.roleid in('2','6')

