select count(t.id) from teacher t left join unit u on u.id = t.unitid left join department d on d.id = t.depid, role r where t.id in (select tid from teacher_permission where cid = #{cid,jdbcType=VARCHAR} group by tid) and r.id = t.roleid and r.id != 1 and t.state = 1 and t.id != #{uid,jdbcType=VARCHAR}
